{
  "verses": [
    {
      "n": 17,
      "column": "left",
      "text": "Bet zik dahrgas irr man\nak STIPRAJS DEEWS!\ntawas Dohmas? zik leels irr\nwinnu Daudsums?\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Bij man tohs skaittht'/\ntad buhs winnu wairak ne ka\nSmiltis/ kad es usmohstohs/\ntad esmu es wehl pee terwis.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Ak Deetws! kaut tu to\nBesdeewigu nokautu/ un tee\nAhinswainigee no mannim at-\nstahtu.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Kas no tewis ar Saimo-\ntchanu runna/ un tawi Eenaid-\nneeki leppojahs welti.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Es jo ak KUNGS! ee-\nnhstu tohs/ kas tew eenihst/ un\nman reebjahs/ kad tee prett tewi\nzelfahs.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Es eenihstu tohs ar gan-\nschu Eenihdefchanu/(tadebl) tee\nirr man par Eenaidneekeem.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Pahrbaudi mann ak\nDeetws! un atsihsti mannw Sir-\ndi/ isluhko mann/ un atsihsti\nmannas Dohmas.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Un luhko/ arrig es us ne-\ngantu Zettu efinu/ un waddi\nmann us to muhschigu Zettu.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Eena Dahwida D\nma/ preeksch ta au\nDseedataja.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Isglabb mann KUNG\nno teem ufkneem Zilwekeem/\nraujt mann no teem War\nDarritajeem.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Kas tanuu dohma fa\nSirdi/ kas ikdeenas us Kan-\nnu fa-eet.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Tee trin fawas Meh-\nka weena Tschubfka/ Ohd\nDsellons irr appafsch wi-\nLuhpahn/Sela.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Pasargi mann KUNG\nno to Besdeewigu Rohkahm/\nglahb mann no teem War-\nDarritajeem/ kas mannas K\njas dohma nostuunt.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Tee Lepnee leek man W\ngus/ un isplefch preeksch m\nWirwes par Tibflu Zett-Mal\nun darra preefsch man Glasd-\nSela.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Es fakku us to KUNG\nTu efi mans STIPRAJ\nDEEWS/ atgreef tahs Au\nak KUNGS! pee mann\nSirde Luhgschanas Balsi.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "KUNGS/ Kungs/ na-\nna spehziga Bestifchana/ tu a\nsedf mannu Galwu Kautchan\nLaika.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Ne dohd ak KUNG\nTam Besdeewigam pehz faw\nKahrtbas/ un lai winna Appre-\nfchanai ne isdohdahs/ zittadi\nlepposees/ Sela.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tas Dsellons to/ kas a\nkahrt mann mettahs/ un ta �\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
